#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-27

# Integration test for scripts/cc-stale-belowfloor.sh — labels below-floor
# cc-adoption FEATURE issues `cc-stale` (never closes them). Mocks `gh` via
# PATH-shadow so cases run with no GitHub API access.
#
# Cases:
#   1. below-floor feature issue → labeled + commented
#   2. at/above-floor issue → untouched
#   3. already cc-stale → skipped (no re-label)
#   4. non-version issue (manual-triage / rotation) → ignored
#   5. DRY_RUN=1 → zero mutations
#   6. label missing → created once

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'

PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}✗${NC} $1 — $2"; FAIL=$((FAIL + 1)); }

count_calls() {
  local pattern="$1"
  if [ ! -s "$MOCK_LOG" ]; then echo 0; return; fi
  local n
  n=$(grep -cE "${pattern}" "$MOCK_LOG" 2>/dev/null) || n=0  # silent: known-noise
  echo "$n"
}

echo "CC Stale Below-Floor — labeling sweep tests"
echo "========================================================="

MOCK_DIR=$(mktemp -d)
MOCK_LOG="$MOCK_DIR/gh.log"
export MOCK_LOG
cat > "$MOCK_DIR/gh" <<'MOCK'
#!/usr/bin/env bash
# gh mock: records every call, emits canned label/issue data from env.
#   MOCK_LABELS      newline-separated existing label names
#   MOCK_ISSUES_TSV  "<num>\t<title>\t<labels-csv>" lines for `issue list`
set -euo pipefail
printf '%s\n' "$*" >> "$MOCK_LOG"
case "$1" in
  label)
    case "$2" in
      list)
        if [ "${MOCK_LABEL_LIST_FAIL:-0}" = "1" ]; then echo "gh: HTTP 403 secondary rate limit" >&2; exit 1; fi
        printf '%s\n' "${MOCK_LABELS:-}"; exit 0 ;;
      create)
        if [ "${MOCK_LABEL_CREATE_EXISTS:-0}" = "1" ]; then echo "GraphQL: Name has already been taken (createLabel)" >&2; exit 1; fi
        exit 0 ;;
    esac
    exit 0
    ;;
  issue)
    case "$2" in
      list) printf '%s\n' "${MOCK_ISSUES_TSV:-}" ;;
      edit) : ;;
      comment) : ;;
    esac
    exit 0
    ;;
esac
echo "MOCK_GH unhandled: $*" >&2
exit 1
MOCK
chmod +x "$MOCK_DIR/gh"
export PATH="$MOCK_DIR:$PATH"

WORK=$(mktemp -d)
cleanup() { rm -rf "$MOCK_DIR" "$WORK"; }
trap cleanup EXIT

if [ "$(command -v gh)" != "$MOCK_DIR/gh" ]; then
  echo "FATAL: mock gh not on PATH"; exit 1
fi

# Fixture support file: floor = 2.1.148.
echo '{"supported_floor":"2.1.148"}' > "$WORK/cc-support.json"
SCRIPT="$PROJECT_ROOT/scripts/cc-stale-belowfloor.sh"

# Mixed issue set with real tabs.
ISSUES=$(printf '%s\t%s\t%s\n' \
  100 'adopt CC 2.1.140 feature: foo (new_perm)' 'cc-adoption,automation' \
  101 'adopt CC 2.1.150 feature: bar (new_command)' 'cc-adoption' \
  102 'adopt CC 2.1.142 feature: baz (new_field)' 'cc-adoption,cc-stale' \
  103 'CC adoption: manual triage needed for 2.1.151' 'cc-adoption')

EDIT_RE='^issue edit [0-9]+ .* --add-label cc-stale'
COMMENT_RE='^issue comment [0-9]+'
CREATE_RE='^label create cc-stale'

# ============================================================================
# Case 1-4: one below-floor issue (#100) labeled; others untouched
# ============================================================================
: > "$MOCK_LOG"
EXIT=0
MOCK_LABELS=$'cc-adoption\nbug' MOCK_ISSUES_TSV="$ISSUES" SLEEP_BETWEEN=0 \
  GH_REPO="acme/orchestkit" SUPPORT_FILE="$WORK/cc-support.json" \
  bash "$SCRIPT" >/tmp/stale-1.out 2>&1 || EXIT=$?
EDITS=$(count_calls "$EDIT_RE")
COMMENTS=$(count_calls "$COMMENT_RE")
if [ "$EXIT" = "0" ] && [ "$EDITS" = "1" ]; then
  log_pass "labels exactly 1 below-floor issue (#100 @ 2.1.140 < 2.1.148)"
else
  log_fail "below-floor labeling" "expected 1 edit, got $EDITS (exit=$EXIT, see /tmp/stale-1.out)"
fi
if [ "$COMMENTS" = "1" ]; then
  log_pass "comments the labeled issue once"
else
  log_fail "comment" "expected 1 comment, got $COMMENTS"
fi
# #100 labeled, NOT #101 (above), #102 (already stale), #103 (no version)
if grep -qE '^issue edit 100 ' "$MOCK_LOG" \
   && ! grep -qE '^issue edit (101|102|103) ' "$MOCK_LOG"; then
  log_pass "skips above-floor (#101), already-stale (#102), non-version (#103)"
else
  log_fail "selectivity" "wrong issues labeled (see $MOCK_LOG)"
fi
# label was missing → created once
if [ "$(count_calls "$CREATE_RE")" = "1" ]; then
  log_pass "creates missing cc-stale label once"
else
  log_fail "label create" "expected 1 create, got $(count_calls "$CREATE_RE")"
fi

# ============================================================================
# Case 5: DRY_RUN=1 → zero mutations
# ============================================================================
: > "$MOCK_LOG"
EXIT=0
DRY_RUN=1 MOCK_LABELS=$'cc-adoption' MOCK_ISSUES_TSV="$ISSUES" \
  GH_REPO="acme/orchestkit" SUPPORT_FILE="$WORK/cc-support.json" \
  bash "$SCRIPT" >/tmp/stale-5.out 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ] \
  && [ "$(count_calls "$EDIT_RE")" = "0" ] \
  && [ "$(count_calls "$COMMENT_RE")" = "0" ] \
  && [ "$(count_calls "$CREATE_RE")" = "0" ] \
  && grep -q "DRY_RUN: would label #100" /tmp/stale-5.out; then
  log_pass "DRY_RUN: prints intent, zero mutations"
else
  log_fail "DRY_RUN" "expected 0 mutations + 'would label' (see /tmp/stale-5.out)"
fi

# ============================================================================
# Case 6: no supported_floor → no-op
# ============================================================================
: > "$MOCK_LOG"
echo '{}' > "$WORK/no-floor.json"
EXIT=0
MOCK_ISSUES_TSV="$ISSUES" GH_REPO="acme/orchestkit" SUPPORT_FILE="$WORK/no-floor.json" \
  bash "$SCRIPT" >/tmp/stale-6.out 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ] && grep -q "no supported_floor" /tmp/stale-6.out; then
  log_pass "no floor → graceful no-op"
else
  log_fail "no-floor" "expected graceful no-op (see /tmp/stale-6.out)"
fi

# ============================================================================
# Case 7: gh label list fails (transient 403) → propagate exit 1, no cascade.
# Regression guard for the cron-tick death that occurred at the LIST stage.
# ============================================================================
: > "$MOCK_LOG"
EXIT=0
MOCK_LABEL_LIST_FAIL=1 MOCK_ISSUES_TSV="$ISSUES" \
  GH_REPO="acme/orchestkit" SUPPORT_FILE="$WORK/cc-support.json" \
  bash "$SCRIPT" >/tmp/stale-7.out 2>&1 || EXIT=$?
if [ "$EXIT" = "1" ] && grep -qE "gh label list.* failed" /tmp/stale-7.out && [ "$(count_calls "$EDIT_RE")" = "0" ]; then
  log_pass "list 403: propagates exit 1 loudly, no cascade to create/edit"
else
  log_fail "list-fail resilience" "expected exit 1 + no edits (see /tmp/stale-7.out)"
fi

# ============================================================================
# Case 8: gh label create races ("Name has already been taken") → tolerated.
# ============================================================================
: > "$MOCK_LOG"
EXIT=0
MOCK_LABELS=$'cc-adoption' MOCK_LABEL_CREATE_EXISTS=1 MOCK_ISSUES_TSV="$ISSUES" SLEEP_BETWEEN=0 \
  GH_REPO="acme/orchestkit" SUPPORT_FILE="$WORK/cc-support.json" \
  bash "$SCRIPT" >/tmp/stale-8.out 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ] && grep -qi "already exists (race)" /tmp/stale-8.out && [ "$(count_calls "$EDIT_RE")" = "1" ]; then
  log_pass "create race: tolerated, run continues to label the below-floor issue"
else
  log_fail "create-race resilience" "expected exit 0 + race-tolerated + 1 edit (see /tmp/stale-8.out)"
fi

echo "========================================================="
echo -e "Passed: ${GREEN}${PASS}${NC}  Failed: ${RED}${FAIL}${NC}"
[ "$FAIL" -eq 0 ]
